// Prayer training: kill men, pick up bones, bury them
import { createBot } from './exec-code.ts';

const { sdk, bot } = await createBot();

async function buryBone(slot: number): Promise<boolean> {
    const state = sdk.getState();
    if (!state) return false;
    const item = state.inventory.find((i: any) => i.slot === slot);
    if (!item) return false;

    // Find bury option
    const buryOpt = item.optionsWithIndex?.find((o: any) => /bury/i.test(o.text));
    const opIndex = buryOpt?.opIndex ?? 1;

    const result = await sdk.sendUseItem(slot, opIndex);
    if (result.success) {
        // Wait for bone to disappear from that slot
        await sdk.waitForCondition((s: any) => !s.inventory.find((i: any) => i.slot === slot && i.id === item.id), 3000).catch(() => {});
    }
    return result.success;
}

